      num_buckets_(n_leading_bits <= 0 ? 1 : (1U << n_leading_bits)),
      dense_bucket_(num_buckets_, std::bitset<DENSE_BUCKET_SIZE>(0)),
      cardinality_(0) {}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ <= 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate hash of the element
  hash_t hash = CalculateHash(val);

  // Extract the first n_leading_bits to determine bucket index
  uint32_t bucket_idx = hash & ((1U << n_leading_bits_) - 1);

  // Shift hash right by n_leading_bits to get the remaining bits
  hash_t remaining_bits = hash >> n_leading_bits_;

  // Find the position of the leftmost 1 bit
  uint64_t position = 0;
  hash_t temp = remaining_bits;
  while (temp != 0 && position < 64) {
    position++;
    temp >>= 1;
  }

  // Split position into dense (lower 4 bits) and overflow (upper 3 bits)
  uint8_t dense_val = position & ((1U << DENSE_BUCKET_SIZE) - 1);  // Lower 4 bits
  uint8_t overflow_val = position >> DENSE_BUCKET_SIZE;             // Upper 3 bits

  // Update dense bucket with max value
  if (dense_val > dense_bucket_[bucket_idx].to_ulong()) {
    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(dense_val);

    // Update overflow bucket if needed
    auto it = overflow_bucket_.find(bucket_idx);
    if (it == overflow_bucket_.end()) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
    } else if (overflow_val > it->second.to_ulong()) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
    }
  } else if (dense_val == dense_bucket_[bucket_idx].to_ulong()) {
    // If dense values are equal, update overflow with max
    auto it = overflow_bucket_.find(bucket_idx);
    if (it == overflow_bucket_.end()) {
      if (overflow_val > 0) {
        overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
      }
    } else if (overflow_val > it->second.to_ulong()) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
    }
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  std::lock_guard<std::mutex> lock(mutex_);

  if (n_leading_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  // Calculate the raw estimate using harmonic mean
  double raw_estimate = 0.0;
  for (uint32_t i = 0; i < num_buckets_; ++i) {
    // Reconstruct full position from dense and overflow buckets
    uint64_t full_position = dense_bucket_[i].to_ulong();
    auto it = overflow_bucket_.find(i);
    if (it != overflow_bucket_.end()) {
      full_position |= (it->second.to_ulong() << DENSE_BUCKET_SIZE);
    }

    raw_estimate += std::pow(2.0, -static_cast<double>(full_position));
  }

  // Apply the HyperLogLog formula
  double alpha = CONSTANT;
  cardinality_ = static_cast<uint64_t>(alpha * num_buckets_ * num_buckets_ / raw_estimate);
}

